FUNCTION CreateProcess(programName)
BEGIN
  // Allocate new PCB from kernel memory
  newPCB ← AllocateBlock()

  // Initialize PCB fields
  newPCB.pid ← GenerateUniquePID()
  newPCB.state ← NEW
  newPCB.programCounter ← 0
  newPCB.cpuRegisters ← {0}
  newPCB.priority ← DEFAULT_PRIORITY
  newPCB.parentPid ← CurrentProcess.pid

  // Allocate memory for process
  newPCB.memoryInfo ← AllocateMemory(PROCESS_SIZE)

  // Load program into memory
  LoadProgram(newPCB, programName)

  // Add to appropriate queue
  AddToReadyQueue(newPCB)
  newPCB.state ← READY

  RETURN newPCB.pid
END

#include <stdio.h>
#include <unistd.h>
#include <sys/types.h>

int main() {
    pid_t pid;

    printf("Parent Process: PID = %d\n", getpid());

    // Create child process
    pid = fork();

    if (pid < 0) {
        // Error in fork
        fprintf(stderr, "Fork Failed\n");
        return 1;
    }
    else if (pid == 0) {
        // Child process
        printf("Child Process: PID = %d, Parent PID = %d\n", 
               getpid(), getppid());
        printf("Child executing...\n");

        // Execute new program (optional)
        // execlp("ls", "ls", "-l", NULL);

        return 0;
    }
    else {
        // Parent process
        printf("Parent: Child created with PID = %d\n", pid);
        printf("Parent waiting for child...\n");
        wait(NULL);  // Wait for child to complete
        printf("Child terminated\n");
    }

    return 0;
}
